// Java 26 - Vector API incubator (JEP 529)
// Learn: process numeric arrays with jdk.incubator.vector lanes.
import jdk.incubator.vector.FloatVector;
import jdk.incubator.vector.VectorSpecies;

VectorSpecies<Float> species = FloatVector.SPECIES_PREFERRED;
float[] result = new float[left.length];
int i = 0;
for (; i < species.loopBound(left.length); i += species.length()) {
    var va = FloatVector.fromArray(species, left, i);
    var vb = FloatVector.fromArray(species, right, i);
    va.add(vb).intoArray(result, i); // lane-wise vector addition
}
for (; i < left.length; i++) {
    result[i] = left[i] + right[i];
}
